The reference solution of that problem in Typescript is 
function solve(n: number, m: number, k: number): number {
    if (k === 0) {
        return n * m; // Each cell needs its own sensor
    }

    // If k is large enough to cover the entire grid, only one sensor is needed
    if (k >= Math.max(n, m) / 2) {
        return 1;
    }

    // For a grid, the minimum number of sensors needed is determined by the number of rows and columns
    // We can place sensors in a grid pattern that covers the entire area with their coverage
    // The formula is ceil(n / (k + 1)) * ceil(m / (k + 1))
    const rows = Math.ceil(n / (k + 1));
    const cols = Math.ceil(m / (k + 1));

    return rows * cols;
}

